"""HTTP API 请求处理器。"""

def log_message(self, format, *args):
    """简化日志。"""
    print(f"[API] {self.command} {self.path}", file=sys.stderr)

def _send_json(self, data: dict, status: int = 200):

    self.wfile.write(json.dumps(data, ensure_ascii=False).encode("utf-8"))

def _read_body(self) -> dict:
    content_len = int(self.headers.get("Content-Length", 0))
    if content_len == 0:
        return {}
    body = self.rfile.read(content_len)
    return json.loads(body) if body else {}

def do_OPTIONS(self):

    return json.loads(body) if body else {}

def do_OPTIONS(self):
    """CORS 预检。"""
    self.send_response(204)
    self.send_header("Access-Control-Allow-Origin", "*")
    self.send_header("Access-Control-Allow-Methods", "GET, POST, OPTIONS")
    self.send_header("Access-Control-Allow-Headers", "Content-Type")
    self.end_headers()

def do_GET(self):

    self.end_headers()

def do_GET(self):
    try:
        self._handle_get()
    except Exception as e:
        self._send_json({"error": str(e), "type": type(e).__name__}, 500)

def do_POST(self):

        self._send_json({"error": str(e), "type": type(e).__name__}, 500)

def do_POST(self):
    try:
        self._handle_post()
    except Exception as e:
        self._send_json({"error": str(e), "type": type(e).__name__}, 500)

def _handle_get(self):

        self._send_json({"error": str(e), "type": type(e).__name__}, 500)

def _handle_get(self):
    path = self.path.split("?")[0]  # 去掉查询参数

    if path == "/info":
        w, h = get_screen_size()
        self._send_json({
            "screen_width": w,
            "screen_height": h,
            "dpi_scale": get_dpi_scale(),
        })

    elif path == "/screenshot":
        img_bytes = screen.screenshot(format="jpeg", quality=85)
        self.send_response(200)
        self.send_header("Content-Type", "image/jpeg")
        self.send_header("Content-Length", str(len(img_bytes)))
        self.send_header("Access-Control-Allow-Origin", "*")
        self.end_headers()
        self.wfile.write(img_bytes)

    elif path == "/cursor":
        x, y = get_cursor_pos()
        self._send_json({"x": x, "y": y})

    elif path == "/windows":
        windows = window.list_windows()
        self._send_json({"windows": windows, "count": len(windows)})

    elif path == "/foreground":
        self._send_json(window.get_foreground_window())

    # v1 兼容
    elif path == "/region":
        w, h = get_screen_size()
        self._send_json({
            "x": 0, "y": 0, "width": w, "height": h,
            "mode": "fullscreen", "timestamp": time.time()
        })

    elif path == "/state":
        x, y = get_cursor_pos()
        self._send_json({
            "mouse_x": x, "mouse_y": y,
            "is_clicking": False, "overlay_visible": True,
            "timestamp": time.time()
        })

    else:
        self._send_json({"error": "Not found", "path": path}, 404)

